import{_ as n,o as a,c as e,ak as p}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"工程化与运维","description":"","frontmatter":{},"headers":[],"relativePath":"devops/index.md","filePath":"devops/index.md","lastUpdated":1774320699000}'),r={name:"devops/index.md"};function t(l,s,i,d,c,o){return a(),e("div",null,[...s[0]||(s[0]=[p(`<h1 id="工程化与运维" tabindex="-1">工程化与运维 <a class="header-anchor" href="#工程化与运维" aria-label="Permalink to “工程化与运维”">​</a></h1><p>Docker 改变了软件的交付方式，Kubernetes 重新定义了服务的部署理念，而 CI/CD 则是连接代码与生产的血管。</p><p>很多人对 DevOps 的理解还停留在「写脚本自动化部署」的层面。但真正的 DevOps 是一套文化和方法论：开发与运维的边界被打破，交付效率和质量被同等重视，持续集成、持续交付、基础设施即代码、监控可观测性——每一个环节都是为了让软件更快、更稳、更安全地到达用户手中。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>篇数</th><th>核心目标</th></tr></thead><tbody><tr><td><a href="/devops/docker/index">Docker</a></td><td>21 篇</td><td>镜像构建、数据持久化、网络通信、Swarm 集群</td></tr><tr><td><a href="/devops/k8s/index">Kubernetes（K8s）</a></td><td>53 篇</td><td>核心概念、存储网络、安全运维、Helm、云原生生态</td></tr><tr><td><a href="/devops/cicd/index">CI/CD</a></td><td>23 篇</td><td>Git、Jenkins、现代 CI/CD 工具链、流水线最佳实践</td></tr><tr><td><a href="/devops/orchestration/index">容器编排对比</a></td><td>4 篇</td><td>Swarm/K8s/Mesos 选型决策、K3s/K0s 轻量方案</td></tr><tr><td><a href="/devops/automation/index">自动化运维</a></td><td>19 篇</td><td>Ansible、Prometheus + Grafana、ELK/EFK/Loki 日志体系</td></tr><tr><td><a href="/devops/kubesphere/index">KubeSphere</a></td><td>24 篇</td><td>企业级容器平台、多租户、DevOps、服务网格</td></tr><tr><td><a href="/devops/iac/index">基础设施即代码（IaC）</a></td><td>4 篇</td><td>Terraform、Pulumi、模块化与状态管理</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：Docker 入门（1-2 周）</span></span>
<span class="line"><span>→ 理解镜像、容器、仓库三大核心概念</span></span>
<span class="line"><span>→ 掌握 Dockerfile 编写与镜像构建</span></span>
<span class="line"><span>→ 数据持久化与网络通信</span></span>
<span class="line"><span>→ Docker Compose 多容器编排</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：Kubernetes 进阶（2-3 周）</span></span>
<span class="line"><span>→ 核心资源对象：Pod、Deployment、Service、ConfigMap</span></span>
<span class="line"><span>→ 深入网络模型与存储抽象</span></span>
<span class="line"><span>→ 安全配置：RBAC、Security Context、NetworkPolicy</span></span>
<span class="line"><span>→ 集群管理与监控：Prometheus + Grafana</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：CI/CD 与工程化（1-2 周）</span></span>
<span class="line"><span>→ Git 工作流与提交规范</span></span>
<span class="line"><span>→ Jenkins 流水线设计与现代 CI/CD 工具</span></span>
<span class="line"><span>→ 镜像安全扫描与制品管理</span></span>
<span class="line"><span>→ 蓝绿部署、金丝雀发布与 GitOps</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：运维体系与自动化（1-2 周）</span></span>
<span class="line"><span>→ Ansible 配置管理</span></span>
<span class="line"><span>→ 日志收集与分析（ELK/EFK/Loki）</span></span>
<span class="line"><span>→ 可观测性：指标 + 日志 + 链路追踪</span></span>
<span class="line"><span>→ 基础设施即代码：Terraform 与 Pulumi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>工程化与运维的面试，核心考察的是你对「软件交付全流程」的把控能力：</p><ol><li><strong>容器化理解</strong>：能不能讲清楚 Docker 的镜像分层原理？Copy-on-Write 带来了什么？多阶段构建解决了什么问题？</li><li><strong>编排思想</strong>：声明式配置 vs 指令式配置的本质区别是什么？Kubernetes 为什么选择前者？</li><li><strong>可观测性意识</strong>：监控和日志在排查问题时各自扮演什么角色？如何避免告警疲劳？</li><li><strong>工程化判断</strong>：哪些环节应该自动化？为什么？IaC 和配置管理的边界在哪里？</li></ol><blockquote><p>&quot;DevOps 不是岗位，是文化。把部署当作开发的一部分，把运维当作产品的延伸——这才是 DevOps 的精髓。&quot;</p></blockquote>`,11)])])}const u=n(r,[["render",t]]);export{h as __pageData,u as default};
